import math

def is_pentagonal(n):
    if n < 1: return False
    val = (math.sqrt(24 * n + 1) + 1) / 6
    return val.is_integer()

def solution():
    # Every hexagonal number is a triangle number (H_n = T_{2n-1})
    # So we only need to generate hexagonal numbers and check if they are pentagonal.
    n = 144 # Start after H_143 = 40755
    while True:
        hex_num = n * (2 * n - 1)
        if is_pentagonal(hex_num):
            return hex_num
        n += 1


if __name__ == "__main__":
    print(solution())
